#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld", &N);
        long long ans = (N/2) * 3LL;
        printf("%lld\n", ans);
    }
    return 0;
}

